#ifndef NUMBER_THREADS
#define NUMBER_THREADS 256
#endif

#ifndef FP_TYPE_DEFINED
typedef float fp;
#endif

__kernel void extract_kernel(long d_Ne,
                             __global fp *d_I) {
    int ei = (int)get_global_id(0);
    if ((long)ei < d_Ne) {
        d_I[ei] = exp(d_I[ei] / (fp)255.0f);
    }
}

__kernel void prepare_kernel(long d_Ne,
                             __global fp *d_I,
                             __global fp *d_sums,
                             __global fp *d_sums2) {
    int ei = (int)get_global_id(0);
    if ((long)ei < d_Ne) {
        fp v = d_I[ei];
        d_sums[ei] = v;
        d_sums2[ei] = v * v;
    }
}

__kernel void reduce_kernel(long d_Ne,
                            long d_no,
                            int d_mul,
                            __global fp *d_sums,
                            __global fp *d_sums2,
                            int blocks_work_size) {
    (void)d_Ne;
    (void)blocks_work_size;

    int lid = (int)get_local_id(0);
    int gid = (int)get_global_id(0);
    int group = (int)get_group_id(0);
    int lsize = (int)get_local_size(0);

    __local fp lsum[NUMBER_THREADS];
    __local fp lsum2[NUMBER_THREADS];

    fp v = (fp)0.0f;
    fp v2 = (fp)0.0f;

    if ((long)gid < d_no) {
        long idx = (long)gid * (long)d_mul;
        v = d_sums[idx];
        v2 = d_sums2[idx];
    }

    lsum[lid] = v;
    lsum2[lid] = v2;
    barrier(CLK_LOCAL_MEM_FENCE);

    int valid = (int)(d_no - (long)group * (long)lsize);
    if (valid < 0) valid = 0;
    if (valid > lsize) valid = lsize;

    for (int offset = lsize >> 1; offset > 0; offset >>= 1) {
        if (lid < offset && (lid + offset) < valid) {
            lsum[lid] += lsum[lid + offset];
            lsum2[lid] += lsum2[lid + offset];
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    if (lid == 0 && valid > 0) {
        long out = (long)group * (long)d_mul * (long)lsize;
        d_sums[out] = lsum[0];
        d_sums2[out] = lsum2[0];
    }
}

__kernel void srad_kernel(fp lambda,
                          int Nr,
                          int Nc,
                          long Ne,
                          __global int *iN,
                          __global int *iS,
                          __global int *jE,
                          __global int *jW,
                          __global fp *d_dN,
                          __global fp *d_dS,
                          __global fp *d_dW,
                          __global fp *d_dE,
                          fp q0sqr,
                          __global fp *d_c,
                          __global fp *d_I) {
    (void)lambda;

    int ei = (int)get_global_id(0);
    if ((long)ei >= Ne) return;

    int row = ei / Nc;
    int col = ei - row * Nc;

    fp Jc = d_I[ei];

    int N = iN[row];
    int S = iS[row];
    int W = jW[col];
    int E = jE[col];

    fp dN = d_I[N * Nc + col] - Jc;
    fp dS = d_I[S * Nc + col] - Jc;
    fp dW = d_I[row * Nc + W] - Jc;
    fp dE = d_I[row * Nc + E] - Jc;

    d_dN[ei] = dN;
    d_dS[ei] = dS;
    d_dW[ei] = dW;
    d_dE[ei] = dE;

    fp G2 = (dN * dN + dS * dS + dW * dW + dE * dE) / (Jc * Jc);
    fp L = (dN + dS + dW + dE) / Jc;

    fp num = ((fp)0.5f * G2) - ((fp)0.0625f * L * L);
    fp den = (fp)1.0f + ((fp)0.25f * L);
    fp qsqr = num / (den * den);

    den = (qsqr - q0sqr) / (q0sqr * ((fp)1.0f + q0sqr));
    fp c = (fp)1.0f / ((fp)1.0f + den);

    if (c < (fp)0.0f) c = (fp)0.0f;
    else if (c > (fp)1.0f) c = (fp)1.0f;

    d_c[ei] = c;

    (void)Nr;
}

__kernel void srad2_kernel(fp lambda,
                           int Nr,
                           int Nc,
                           long Ne,
                           __global int *iN,
                           __global int *iS,
                           __global int *jE,
                           __global int *jW,
                           __global fp *d_dN,
                           __global fp *d_dS,
                           __global fp *d_dW,
                           __global fp *d_dE,
                           __global fp *d_c,
                           __global fp *d_I) {
    int ei = (int)get_global_id(0);
    if ((long)ei >= Ne) return;

    int row = ei / Nc;
    int col = ei - row * Nc;

    fp cN = d_c[ei];
    fp cS = d_c[iS[row] * Nc + col];
    fp cW = d_c[ei];
    fp cE = d_c[row * Nc + jE[col]];

    fp D = cN * d_dN[ei] + cS * d_dS[ei] + cW * d_dW[ei] + cE * d_dE[ei];

    d_I[ei] = d_I[ei] + ((fp)0.25f * lambda * D);

    (void)Nr;
    (void)iN;
    (void)jW;
}

__kernel void compress_kernel(long d_Ne,
                              __global fp *d_I) {
    int ei = (int)get_global_id(0);
    if ((long)ei < d_Ne) {
        d_I[ei] = log(d_I[ei]) * (fp)255.0f;
    }
}
